/**
 * Webhook notification handler — fires HTTP callbacks to registered URLs
 * in response to order lifecycle events.
 *
 * Follows the same event-driven pattern as NotificationService and
 * EmailNotificationHandler: subscribes to EventBus events and handles
 * them independently, with no direct coupling to producing services.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType } from '../events/event-types.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  status: 'success' | 'failure';
  deliveredAt: Date;
}

export type WebhookSender = (url: string, payload: Record<string, unknown>) => Promise<boolean>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookNotificationHandler {
  private logger = new Logger('WebhookNotificationHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(
    private eventBus: EventBus,
    sender?: WebhookSender,
  ) {
    // Default sender simulates a successful HTTP POST.
    // In production, this would use fetch() or an HTTP client.
    this.sender = sender ?? (async () => true);
    this.registerHandlers();
  }

  /**
   * Register event handlers for webhook triggers.
   * All events are received via EventBus subscriptions.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleEvent('order:created', {
        eventType: 'order:created',
        orderId: event.order.id,
        userId: event.order.userId,
        items: event.order.items,
        total: event.order.total,
        status: event.order.status,
        timestamp: event.timestamp.toISOString(),
      });
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleEvent('order:status-changed', {
        eventType: 'order:status-changed',
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
        timestamp: event.timestamp.toISOString(),
      });
    });
  }

  /**
   * Dispatch webhook deliveries to all URLs registered for the given event type.
   */
  private async handleEvent(
    eventType: EventType,
    payload: Record<string, unknown>,
  ): Promise<void> {
    const matchingRegistrations = this.registrations.filter(
      (r) => r.eventType === eventType,
    );

    for (const registration of matchingRegistrations) {
      this.logger.info(
        `Delivering webhook ${registration.id} to ${registration.url} for ${eventType}`,
      );

      let status: 'success' | 'failure';
      try {
        const ok = await this.sender(registration.url, payload);
        status = ok ? 'success' : 'failure';
      } catch {
        status = 'failure';
      }

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        status,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);

      this.logger.info(
        `Webhook delivery ${delivery.id}: ${status} for ${registration.url}`,
      );
    }
  }

  /**
   * Register a URL to receive callbacks for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(
      `Registered webhook ${registration.id}: ${url} for ${eventType}`,
    );
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Unregistered webhook ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook registration.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

