      total: 20,
      status: newStatus as OrderStatusChangedEvent['order']['status'],
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date('2024-01-01T00:00:00Z'),
  });

  describe('webhook registration', () => {
    it('should register a webhook and return the registration', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should generate sequential webhook IDs', () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      const reg2 = handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(reg1.id).toBe('webhook-0001');
      expect(reg2.id).toBe('webhook-0002');
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');
      handler.registerWebhook('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://a.com/hook', 'order:created');
      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhook delivery', () => {
    it('should deliver to registered webhooks on order created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).toHaveBeenCalledOnce();
      expect(sender).toHaveBeenCalledWith(
        'https://example.com/hook',
        expect.objectContaining({
          eventType: 'order:created',
          orderId: 'order-1',
          userId: 'user-1',
          total: 20,
          status: 'pending',
        }),
      );
    });

    it('should include items in the payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = sender.mock.calls[0]![1] as Record<string, unknown>;
      expect(payload.items).toEqual([
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ]);
    });

    it('should record successful delivery', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
    });

    it('should not deliver to webhooks registered for other event types', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).not.toHaveBeenCalled();
      expect(handler.getDeliveryCount()).toBe(0);
    });

    it('should deliver to multiple registered webhooks', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).toHaveBeenCalledTimes(2);
      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('order:status-changed webhook delivery', () => {
    it('should deliver to registered webhooks on status change', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(sender).toHaveBeenCalledWith(
        'https://example.com/hook',
        expect.objectContaining({
          eventType: 'order:status-changed',
          orderId: 'order-1',
          previousStatus: 'pending',
          newStatus: 'confirmed',
        }),
      );
    });

    it('should record delivery for status change', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });
  });

  describe('delivery failure handling', () => {
    it('should record failure when sender returns false', async () => {
      sender.mockResolvedValue(false);
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
    });

    it('should record failure when sender throws', async () => {
      sender.mockRejectedValue(new Error('Network error'));
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
    });
  });

  describe('delivery management', () => {
    it('should generate sequential delivery IDs', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[1]?.id).toBe('delivery-0002');
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(reg1.id)[0]?.url).toBe('https://a.com/hook');
    });

    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clearAll();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();

      const sharedBus = new EventBus();
      const notificationService = new NotificationService(sharedBus);
      const sharedSender = vi.fn().mockResolvedValue(true);
      const webhookHandler = new WebhookNotificationHandler(sharedBus, sharedSender);
      resetWebhookIdCounters();

      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await sharedBus.emit<OrderCreatedEvent>(makeOrderCreatedEvent());

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(webhookHandler.getDeliveryCount()).toBe(1);
      expect(sharedSender).toHaveBeenCalledOnce();
    });
  });
});
